    for (i in 0 until n) {
        dist[i] = Long.MAX_VALUE
    }
    dist[0] = 0L

    val pq = PriorityQueue<MutableList<Long>>()
    pq.add(arrayOf(0L, 0L)) // time, node

    while (pq.isNotEmpty()) {
        val temp = pq.poll()
        val time = temp[0]
        val node = temp[1]

        if (node == n - 1) {
            return time
        }

        if (dist[node] < time) continue

        for (edge in graph[node]) {
            val v = edge[0]
            val start = edge[1]
            val end = edge[2]

            if (start <= time && time <= end) {
                val newTime = time + 1
                if (newTime < dist[v]) {
                    dist[v] = newTime
                    pq.add(arrayOf(newTime, v))
                }
            }
        }
    }

    return -1
}
